import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testHashCode() {
        // Given
        char delimiter = ',';
        Character quoteCharacter = '"';
        QuoteMode quoteMode = QuoteMode.ALL;
        Character commentMarker = '#';
        Character escapeCharacter = '\\';
        String nullString = "NULL";
        boolean ignoreSurroundingSpaces = true;
        boolean ignoreEmptyLines = false;
        boolean skipHeaderRecord = true;
        String recordSeparator = "\n";
        String[] header = {"Header1", "Header2"};

        CSVFormat csvFormat = new CSVFormat(delimiter, quoteCharacter, quoteMode, commentMarker, escapeCharacter,
                ignoreSurroundingSpaces, ignoreEmptyLines, recordSeparator, nullString, header, skipHeaderRecord, true);

        // When
        int hashCode = csvFormat.hashCode();

        // Then
        int expectedHashCode = 31 * (31 * (31 * (31 * (31 * (31 * (31 * (31 * (31 * (31 * (31 * (31 * (31 * (31 * 1 + delimiter)
                + (quoteMode == null ? 0 : quoteMode.hashCode()))
                + (quoteCharacter == null ? 0 : quoteCharacter.hashCode()))
                + (commentMarker == null ? 0 : commentMarker.hashCode()))
                + (escapeCharacter == null ? 0 : escapeCharacter.hashCode()))
                + (nullString == null ? 0 : nullString.hashCode()))
                + (ignoreSurroundingSpaces ? 1231 : 1237))
                + (ignoreEmptyLines ? 1231 : 1237))
                + (skipHeaderRecord ? 1231 : 1237))
                + (recordSeparator == null ? 0 : recordSeparator.hashCode()))
                + header.hashCode();

        assertEquals(expectedHashCode, hashCode);
    }
}
